    {
        var request = Create();
        Assert.True(request.Equals(request));
        Assert.Same(request, request);
    }

    [Fact]
    public void EqualityOperators_AreValueBased()
    {
        var a = Create();
        var b = Create();

        Assert.True(a == b);
        Assert.False(a != b);
    }

    // =====================================================================
    // Non-mutating copy expression (init accessors)
    // =====================================================================

    [Fact]
    public void With_CopiesAllFieldsExceptTheTargetedOne()
    {
